树与图邻接表用head数组为表头，使用ver和edge数组分别存储边的终点和权值，用next数组模拟链表指针。
在一个图中添加一个从x到y边的权值为z的有向边：
int head[maxn &lt;&lt; 2], ver[maxn], edge[maxn], next[maxn &lt;&lt; 2];int tot;//tot表示边的编号 inline void adde(int x, int y, int z) &#123;	ver[++tot] = y;	next[tot] = head[x]; //这句话表示原来x指向的所有边都挂到tot这条新的边的后面。 	head[x] = tot;	edge[tot] = z;//这句话表示在x原来指向的tot边的前面插入了新来的这个边。 &#125;
图从x访问所有x相连的点。
void serch() &#123;	for (int i = head[x]; i; i = next[i]) &#123;		//从x的最后输入的那条边开始，便利所有x为出发点的边。next数组是为指出x出发的每一条边之间的关系。	&#125;&#125;
图从x的一个深度优先遍历。
bool v[maxn];void dfs(int x) &#123;	v[x] = 1;	for (int i=head[x]; i; i = next[i]) &#123;		int y = ver[i];		if (v[y])	continue;		dfs(y);	&#125;&#125;//这个搜索的时间复杂度是O(n+m)。

树的dfs序。
void int(x) &#123;	a[++m] = x;	v[x] = 1;	for (int i = head[x]; i; i = next[i]) &#123;		int y = ver[i];		if(v[y])	continue;		dfs(y);	&#125;	a[++m] = x;&#125;

树的深度。
int d[maxn];void dfs(int x) &#123;	v[x] = 1;	for(int i = head[x]; i; i = next[i]) &#123;		int y = ver[i];		if(v[y])	continue;		d[y] = d[x] + 1;		dfs(y);	&#125;&#125;//d[i]中储存的是编号为i的节点从根节点往下的深度。

树的重心。
定义：设max_part(x)表示再删除节点x后产生的子树中，最大的一颗的大小。是max_part函数取到最小值的节点p就成为整棵树的重心。下面的代码我们可以统计出size数组，并且找到这棵树的重心。
int size[maxn];void dfs(int x) &#123;	v[x] = 1; size[x] = 1;	int max_part = 0;//删掉子树x之后分成的若干个子树中最大的那个的大小 	for (int i=head[x];i;i=next[i]) &#123;		int y = ver[i];		if (v[y])	continue;		dfs(y);		size[x] += size[y];//从子节点向上更新 		max_part = max(max_part, size[y]);//x的子节点中最大的那个节点的size 	&#125;	max_part = max(max_part, n - size[x]);//现在max_part中储存的是删掉x之后形成的若干个子树中最大的那个大小 	if (max_part &lt; ans) &#123;		ans = max_part;		pos = x;//pos中储存的就是这个树的重心的节点号。	&#125; &#125; 

图的连通块的划分
int cnt;void dfs(int x) &#123;	v[x] = cnt;	for (int i=head[x];i;i=next[i]) &#123;		int y = ver[i];		if (v[y])	continue;		dfs(y);	&#125;&#125;for (int i=1;i&lt;=n;++i) &#123;	if(v[i]) continue;	cnt++;	dfs(i);&#125;//cnt值相同的节点在同一个连通块中，cnt值表示连通块的个数。

图的广度优先遍历按照层级进行遍历。
void bfs() &#123;	memset(d, 0, sizeof(d));//d中存储的是每一个节点的深度。	queue&lt;int&gt; q;	q.push(1);d[1] = 1;	while(q.size()) &#123;		int x = q.front();	q.pop();		for (int i=head[x];i;i=next[i]) &#123;			int y = ver[i];			if (d[y]) continue;			d[y] = d[x] + 1;			q.push(y);		&#125; 	&#125;&#125;

拓扑排序这个算法可以判断是否存在环：如果cnt和n不相等的话，那么存在环，因为环中的每一个点的入度都不可能为0。
int deg[maxn];void add(int x, int y, int z) &#123;	ver[++tot] = y;	next[tot] = head[x];	head[x] = tot;	edge[tot] = z;	deg[y]++;&#125;void topsort() &#123;	queue&lt;int&gt; q;	for (int i=1;i&lt;=n;++i)		if (deg[i] == 0)	q.push(i);//如果点的入度为0那么将这个点入队。	while(q.size()) &#123;		int x = q.front(); 	q.pop();		a[++cnt] = x;//将入度为0的那个点输出。		for (int i=head[x];i;i=next[i]) &#123;			int y = ver[i];			if (--deg[y] == 0)	q.push(y);		&#125;	&#125;&#125;int main() &#123;	cin &gt;&gt; n &gt;&gt; m;	for (int i=1;i&lt;=m;++i) &#123;		int x, y;		cin &gt;&gt; x &gt;&gt; y;		adde(x, y, 0);	&#125;	topsort();	for (int i=1;i&lt;=cnt;++i) &#123;		cout &lt;&lt; a[i] &lt;&lt; &#x27; &#x27;;	&#125;&#125;

A题 切蛋糕题目链接 ：https://ac.nowcoder.com/acm/contest/11746/A基本思路是将1/k进行二进制拆分，比如说对于k=5，1 / 5 的二进制为 0.001100110011，则应存在5份大小为0.001的蛋糕，5份大小为0.0001的蛋糕，以此类推。（看到2的几次方相加就应该想到二进制拆分）代码不会写Orz，还不会实现，先留着之后补。
B题 小宝的幸运数组题目链接 ：https://ac.nowcoder.com/acm/contest/11746/B题目的思路大概是一个同余的相互跳的一个搜索之类的东西，很巧妙。
#include&lt;bits/stdc++.h&gt;using namespace std;const int maxn = 1e5 + 10;typedef long long ll;ll T, n, k, ans, sum, t;ll head[maxn];int main() &#123;	for (scanf(&quot;%ld&quot;, &amp;T);T;T--) &#123;//学来的多组处理		scanf(&quot;%ld%ld&quot;, &amp;n, &amp;k);		ans = sum = 0;		for (int i=0;i&lt;=k;++i)	head[i] = -1;//head[x]表示的是第一次出现总和加到一起的余数为x的时候的a的位置是多少。这样可以一边加一边处理，如果某个数加到总和上之后和之前第一次的余数对应上了，说明这之间的数字的和可以被K整除。		head[0] = 0;//显然对于余数为0来说，不需要有数字加上就行。		for (int i=1;i&lt;=n;++i) &#123;			scanf(&quot;%ld&quot;, &amp;t);			sum = (sum + t) % k;//维持一个加上当前值然后在k里的一个特征值。			if (head[sum] != -1) 				ans = max(ans, i - head[sum]);//维护答案 			else 				head[sum] = i;//如果第一次出现的话就保存位置		&#125;		ans = ans == 0 ? -1 : ans;		printf(&quot;%ld\n&quot;, ans);	&#125;	return 0;&#125;
C题 上进的凡凡这道题的思路是：一个非降序数组的所有子串都为非降序，只要把给定数组分为若干个非降序部分（每个部分要尽可能长），然后计算子串数，对于长度为n的数组子串数为 n * (n + 1) / 2，遍历然后相加。思路的正确性：一个非降序数组的所有子串都为非降序串。
#include&lt;bits/stdc++.h&gt;using namespace std;const int maxn = 100005;typedef long long ll;ll a[maxn];ll sum, n;int main() &#123;	ios :: sync_with_stdio(false);	cin &gt;&gt; n;	for (int i = 1; i &lt;= n; i++)	cin &gt;&gt; a[i];	for (ll i = 1,t = 1; i &lt;= n; ) &#123;		t = i;		t++;		while (a[t] &gt;= a[t - 1] &amp;&amp; t &lt;= n)			t++;		ll ans = t - i;		sum += ans * (ans + 1)/2;		i = t;	&#125;	cout &lt;&lt; sum &lt;&lt; endl;	return 0;&#125;
